import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const d={};function l(t,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>redis中有两中持久化方案aof和rdb</p><table><thead><tr><th></th><th>RDB</th><th>AOF</th></tr></thead><tbody><tr><td>持久化方式</td><td>定时对整个内存做快照</td><td>记录每一次执行的命令</td></tr><tr><td>数据完整性</td><td>不完整，两次备份之间会丢失</td><td>相对完整，取决于刷盘策略</td></tr><tr><td>文件大小</td><td>会有压缩，文件体积小</td><td>记录命令，文件体积很大</td></tr><tr><td>岩机恢复速度</td><td>很快</td><td>慢</td></tr><tr><td>数据恢复优先级</td><td>低，因为数据完整性不如AOF</td><td>高，因为数据完整性更高</td></tr><tr><td>系统资源占用</td><td>高，大量CPU和内存消耗</td><td>低，主要是磁盘I0资源.但AOF重写时会占用大量CPU和内存资源</td></tr><tr><td>使用场景</td><td>可以容忍数分钟的数据丢失，追求更快的启动速度</td><td>对数据安全性要求较高常见</td></tr></tbody></table><h1 id="rdb" tabindex="-1"><a class="header-anchor" href="#rdb"><span>RDB</span></a></h1><p>RDB全称RedisDatabaseBackup file（Redis数据备份文件），也被叫做Redis数据快照。简单来说就是把内存中的所有数据都记录到磁盘中。当Redis实例故障重启后，从磁盘读取快照文件，恢复数据。 快照文件称为RDB文件，默认是保存在当前运行目录。</p><p>默认就是rdb持久化,当redis停机时执行,将缓存中的数据持久化到rdb文件中,但因为故障宕机时不会进行,所以会造成数据的丢失</p><p>触发rdb的机制可以再redis.conf文件中找到</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#900秒内，如果至少有1个key被修改，则执行bgsave，如果是save &quot;&quot;则表示禁用RDB</span></span>
<span class="line"><span>save 900 1</span></span>
<span class="line"><span>#300秒内，如果至少有10个key被修改，则执行bgsave</span></span>
<span class="line"><span>save 300 10</span></span>
<span class="line"><span>save 60 10000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#是否压缩，建议不开启，压缩也会消耗cpu，磁盘的话不值钱</span></span>
<span class="line"><span>rdbcompression yes</span></span>
<span class="line"><span>#RDB文件名称</span></span>
<span class="line"><span>dbfilename dump.rdb</span></span>
<span class="line"><span>#文件保存的路径目录</span></span>
<span class="line"><span>dir ./</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>bgsave开始时会fork主进程得到子进程，子进程共享主进程的内存数据。完成fork后读取内存数据并写入 RDB 文件。</p><h1 id="aof" tabindex="-1"><a class="header-anchor" href="#aof"><span>AOF</span></a></h1><p>AOF全称为Append Only File（追加文件）。Redis处理的每一个写命令都会记录在AOF文件，可以看做是命令日志文件。</p><p>AOF默认是关闭的，需要修改redis.conf配置文件来开启AOF：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#是否开启AOF功能，默认是no</span></span>
<span class="line"><span>appendonly yes</span></span>
<span class="line"><span>#AOF文件的名称</span></span>
<span class="line"><span>appendfilename &quot;appendonly.aof&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#表示每执行一次写命令，立即记录到AOF文件</span></span>
<span class="line"><span>appendfsync always</span></span>
<span class="line"><span>#写命令执行完先放入AOF缓冲区，然后表示每隔1秒将缓冲区数据写到AOF文件，是默认方案</span></span>
<span class="line"><span>appendfsync everysec</span></span>
<span class="line"><span>#写命令执行完先放入AOF缓冲区，由操作系统决定何时将缓冲区内容写回磁盘</span></span>
<span class="line"><span>appendfsync no</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在开启aof前还需要禁用rdb</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>save &quot;&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="混合模式" tabindex="-1"><a class="header-anchor" href="#混合模式"><span>混合模式</span></a></h3><p>如果同时开启rdb和aof那么只会加载aof文件而不开启rdb</p><p>开启混合模式后两种方案同时应用</p><ol><li>开启方式 设置<code>aof-use-rdb-preamble</code>的值为yes</li></ol><h3 id="纯缓存模式" tabindex="-1"><a class="header-anchor" href="#纯缓存模式"><span>纯缓存模式</span></a></h3><p>要同时关闭rdb和aof <code>save &quot;&quot;</code>禁用rdb持久化模式后依旧可以使用save,bgsave生成rdb文件 <code>appendonly no</code>禁用aof后依旧可以使用bgrewriteaof生成aof文件</p><h1 id="事务" tabindex="-1"><a class="header-anchor" href="#事务"><span>事务</span></a></h1><p>如果是编译期错误那么在执行前就会报错,且当前事务中的所有命令都被清空 如果是运行时错误,那么在执行后会执行对的命令,只对出错的命令报错</p><ol><li>开启事务 使用multi命令开启事务,开启事务后在执行事务命令前的所有命令都被放在一个事务中执行</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MULLTI</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>执行事务 使用exec命令执行事务</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>EXEC</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>放弃事务</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>DISCARD</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>放弃事务后前面未执行的事务都被清零,此后再次执行命令不会作为事务</p><h1 id="订阅发布" tabindex="-1"><a class="header-anchor" href="#订阅发布"><span>订阅发布</span></a></h1><p>redis的消息即发即失,无法判断消息是否被消费</p><ol><li>订阅</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>SUBSCRIBE 主题名列表</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>订阅的客户端每次收到一个三个参数的消息分别是:消息种类,始发频道的名称,实际的消息内容</p><ol start="2"><li>发布消息</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>PUBLISH 主题名 消息</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>取消订阅</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>UNSUBSCRIBE</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>`,38)]))}const p=e(d,[["render",l]]),c=JSON.parse('{"path":"/tools/redis/4/","title":"4 持久化","lang":"zh-CN","frontmatter":{"title":"4 持久化","createTime":"2025/04/05 12:12:26","permalink":"/tools/redis/4/"},"readingTime":{"minutes":3.54,"words":1061},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/Redis/4 持久化.md","headers":[]}');export{p as comp,c as data};
